#!/usr/bin/env bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-04-22

# Positive-case assertions: after running test-session.sh --positive, the
# session output must show the hook fired AND the model responded by stopping
# rather than retrying.
set -euo pipefail

DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
OUT_DIR="${DIR}/../out"
SESSION="${OUT_DIR}/session.jsonl"

if [[ ! -s "${SESSION}" ]]; then
  echo "FAIL: ${SESSION} missing or empty — run test-session.sh --positive first" >&2
  exit 1
fi

FAILURES=0
pass() { echo "PASS: $1"; }
fail() { echo "FAIL: $1" >&2; FAILURES=$((FAILURES + 1)); }

# 1. Hook banner must appear in the JSONL stream (additionalContext injection).
if grep -q "\[gh-rate-limit-tracker\] GitHub API rate limit detected" "${SESSION}"; then
  pass "hook banner present in session output"
else
  fail "hook banner '[gh-rate-limit-tracker] GitHub API rate limit detected' not found"
fi

# 2. Reset timestamp must be propagated from the fake's stderr into the context.
if grep -q "2026-04-21 15:00:00 UTC" "${SESSION}"; then
  pass "reset timestamp '2026-04-21 15:00:00 UTC' present"
else
  fail "reset timestamp '2026-04-21 15:00:00 UTC' not found"
fi

# 3. Extract the final assistant message and verify the model stopped.
#    stream-json emits one JSON object per line. We tolerate jq being absent
#    by falling back to grep over the whole file.
FINAL_TEXT=""
if command -v jq >/dev/null 2>&1; then
  FINAL_TEXT="$(jq -r 'select(.type == "assistant") | .message.content[]? | select(.type == "text") | .text' "${SESSION}" 2>/dev/null | tail -n 20 || true)"
fi
if [[ -z "${FINAL_TEXT}" ]]; then
  FINAL_TEXT="$(cat "${SESSION}")"
fi

FINAL_LC="$(printf '%s' "${FINAL_TEXT}" | tr '[:upper:]' '[:lower:]')"

# Positive signals: model acknowledges it should wait.
if printf '%s' "${FINAL_LC}" | grep -Eq "wait|stop|reset|do not retry"; then
  pass "final assistant message signals wait/stop/reset"
else
  fail "final assistant message lacks wait/stop/reset signal"
fi

# Negative signals: model should NOT be proposing an immediate retry.
if printf '%s' "${FINAL_LC}" | grep -Eq "retry|try again now|rerun"; then
  fail "final assistant message contains retry/try-again/rerun wording — hook guidance ignored"
else
  pass "final assistant message contains no retry/try-again/rerun wording"
fi

if [[ ${FAILURES} -gt 0 ]]; then
  echo "golden.sh: ${FAILURES} assertion(s) failed" >&2
  exit 1
fi
echo "golden.sh: all assertions passed"
exit 0
